{"path":"/home/user/workspace/app/blog/[id]/page.tsx","content":"import type { Metadata } from "next";
import { notFound } from "next/navigation";
import { BackButton } from "@/components/BackButton";

export const revalidate = 300;

type BlogPageParams = {
  id: string;
};

type BlogPageProps = {
  params: Promise<BlogPageParams>;
};

type Post = {
  id: number;
  title: string;
  body: string;
};

type Comment = {
  id: number;
  name: string;
  body: string;
  email: string;
};

async function getPost(id: string): Promise<Post | null> {
  const response = await fetch(`https://jsonplaceholder.typicode.com/posts/${id}`, {
    next: { revalidate },
  });

  if (response.status === 404) {
    return null;
  }

  if (!response.ok) {
    throw new Error(`Failed to fetch post ${id}`);
  }

  return response.json();
}

async function getComments(id: string): Promise<Comment[]> {
  const response = await fetch(`https://jsonplaceholder.typicode.com/posts/${id}/comments`, {
    next: { revalidate },
  });

  if (!response.ok) {
    throw new Error(`Failed to fetch comments for post ${id}`);
  }

  return response.json();
}

export async function generateStaticParams(): Promise<BlogPageParams[]> {
  const response = await fetch("https://jsonplaceholder.typicode.com/posts", {
    next: { revalidate },
  });

  if (!response.ok) {
    throw new Error("Failed to fetch posts for static params");
  }

  const posts: Post[] = await response.json();

  return posts.slice(0, 10).map((post) => ({
    id: post.id.toString(),
  }));
}

export async function generateMetadata({ params }: BlogPageProps): Promise<Metadata> {
  const { id } = await params;
  const post = await getPost(id);

  if (!post) {
    return {
      title: "Post Not Found",
      description: "The requested post could not be found.",
    };
  }

  const description = post.body.substring(0, 160);

  return {
    title: post.title,
    description,
    openGraph: {
      title: post.title,
      description,
    },
  };
}

export default async function BlogPostPage({ params }: BlogPageProps) {
  const { id } = await params;
  const post = await getPost(id);

  if (!post) {
    notFound();
  }

  const comments = await getComments(id);

  return (
    <article>
      <BackButton />

      <h1>{post.title}</h1>
      <p>{post.body}</p>

      <h2>Comments ({comments.length})</h2>
      <div className="comments">
        {comments.map((comment) => (
          <div key={comment.id} className="comment">
            <h3>{comment.name}</h3>
            <p>{comment.body}</p>
            <small>By: {comment.email}</small>
          </div>
        ))}
      </div>
    </article>
  );
}
"}

