{"path":"/home/user/workspace/app/api/posts/route.ts","content":"import { NextResponse } from "next/server";

type PostRecord = {
  id: number;
  title: string;
  content: string;
  createdAt?: string;
};

type CreatePostBody = {
  title?: string;
  content?: string;
};

export async function GET() {
  const posts: PostRecord[] = [
    { id: 1, title: "First Post", content: "This is the first post" },
    { id: 2, title: "Second Post", content: "This is the second post" },
  ];

  return NextResponse.json(posts);
}

export async function POST(request: Request) {
  const body = (await request.json()) as CreatePostBody;
  const { title, content } = body;

  if (!title || !content) {
    return NextResponse.json({ error: "Title and content are required" }, { status: 400 });
  }

  const newPost: PostRecord = {
    id: Date.now(),
    title,
    content,
    createdAt: new Date().toISOString(),
  };

  return NextResponse.json(newPost, { status: 201 });
}
"}

{"path":"/home/user/workspace/app/api/posts/[id]/route.ts","content":"import { NextResponse } from "next/server";

type RouteContext = {
  params: Promise<{ id: string }>;
};

type PostRecord = {
  id: number;
  title: string;
  content: string;
  createdAt?: string;
  updatedAt?: string;
};

type UpdatePostBody = {
  title?: string;
  content?: string;
};

export async function GET(_request: Request, context: RouteContext) {
  const { id } = await context.params;
  const post: PostRecord = {
    id: Number.parseInt(id, 10),
    title: `Post ${id}`,
    content: `This is the content for post ${id}`,
    createdAt: new Date().toISOString(),
  };

  return NextResponse.json(post);
}

export async function PUT(request: Request, context: RouteContext) {
  const { id } = await context.params;
  const body = (await request.json()) as UpdatePostBody;
  const updatedPost: PostRecord = {
    id: Number.parseInt(id, 10),
    title: body.title || `Post ${id}`,
    content: body.content || `Updated content for post ${id}`,
    updatedAt: new Date().toISOString(),
  };

  return NextResponse.json(updatedPost);
}

export async function DELETE(_request: Request, context: RouteContext) {
  const { id } = await context.params;

  return NextResponse.json({ message: `Post ${id} deleted successfully` });
}
"}

